#ifndef OR_COMBINATOR_H
#define OR_COMBINATOR_H
#include <Arduino.h>

class ORCombinator {
public:
    ORCombinator(int inputCount = 2);
    void setInput(int index, bool value);
    bool compute();
    bool getResult() const;
private:
    bool* _inputs;
    int _count;
    bool _result;
};

#endif

firmware_template.source:
#include "or_combinator.h"

ORCombinator::ORCombinator(int inputCount)
    : _count(inputCount), _result(false) {
    _inputs = new bool[inputCount];
    for (int i = 0; i < inputCount; i++) _inputs[i] = false;
}

void ORCombinator::setInput(int index, bool value) {
    if (index >= 0 && index < _count) _inputs[index] = value;
}

bool ORCombinator::compute() {
    _result = false;
    for (int i = 0; i < _count; i++) {
        if (_inputs[i]) { _result = true; break; }
    }
    return _result;
}

bool ORCombinator::getResult() const { return _result; }
